# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import os
import boto3
import hashlib
import time
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from PIL import Image
import io
from urllib.parse import urlparse
import logging
from datetime import datetime

app = Flask(__name__)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1')
S3_BUCKET = os.environ.get('S3_BUCKET', 'website-screenshots')
CHROME_DRIVER_PATH = os.environ.get('CHROME_DRIVER_PATH', '/usr/bin/chromedriver')
SCREENSHOT_WIDTH = int(os.environ.get('SCREENSHOT_WIDTH', '1280'))
SCREENSHOT_HEIGHT = int(os.environ.get('SCREENSHOT_HEIGHT', '720'))
THUMBNAIL_WIDTH = int(os.environ.get('THUMBNAIL_WIDTH', '400'))
THUMBNAIL_HEIGHT = int(os.environ.get('THUMBNAIL_HEIGHT', '300'))
PAGE_LOAD_TIMEOUT = int(os.environ.get('PAGE_LOAD_TIMEOUT', '30'))

s3_client = boto3.client('s3', region_name=AWS_REGION)

def get_chrome_driver():
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--disable-software-rasterizer')
    chrome_options.add_argument('--disable-extensions')
    chrome_options.add_argument('--disable-infobars')
    chrome_options.add_argument('--ignore-certificate-errors')
    chrome_options.add_argument('--allow-insecure-localhost')
    chrome_options.add_argument(f'--window-size={SCREENSHOT_WIDTH},{SCREENSHOT_HEIGHT}')
    chrome_options.add_argument('--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36')
    
    service = Service(CHROME_DRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    
    return driver

def validate_url(url):
    try:
        result = urlparse(url)
        return all([result.scheme, result.netloc])
    except:
        return False

def generate_url_hash(url):
    return hashlib.md5(url.encode()).hexdigest()

def create_thumbnail(image_data, width, height):
    image = Image.open(io.BytesIO(image_data))
    image.thumbnail((width, height), Image.Resampling.LANCZOS)
    
    output = io.BytesIO()
    image.save(output, format='PNG', optimize=True)
    output.seek(0)
    
    return output.read()

def upload_to_s3(file_data, key, content_type='image/png'):
    try:
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=key,
            Body=file_data,
            ContentType=content_type,
            ACL='public-read'
        )
        
        url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"
        return url
    except Exception as e:
        logger.error(f"Error uploading to S3: {str(e)}")
        raise

def check_screenshot_exists(url_hash):
    try:
        thumbnail_key = f"thumbnails/{url_hash}.png"
        s3_client.head_object(Bucket=S3_BUCKET, Key=thumbnail_key)
        
        thumbnail_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{thumbnail_key}"
        full_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/screenshots/{url_hash}.png"
        
        return {
            'exists': True,
            'thumbnail_url': thumbnail_url,
            'full_url': full_url
        }
    except:
        return {'exists': False}

def capture_screenshot(url):
    driver = None
    try:
        driver = get_chrome_driver()
        
        logger.info(f"Loading URL: {url}")
        driver.get(url)
        
        time.sleep(2)
        
        driver.execute_script("window.scrollTo(0, 0);")
        time.sleep(1)
        
        screenshot_data = driver.get_screenshot_as_png()
        
        return screenshot_data
    except Exception as e:
        logger.error(f"Error capturing screenshot: {str(e)}")
        raise
    finally:
        if driver:
            driver.quit()

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy', 'timestamp': datetime.utcnow().isoformat()})

@app.route('/screenshot', methods=['POST'])
def create_screenshot():
    try:
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({'error': 'URL is required'}), 400
        
        url = data['url']
        force_refresh = data.get('force_refresh', False)
        
        if not validate_url(url):
            return jsonify({'error': 'Invalid URL format'}), 400
        
        url_hash = generate_url_hash(url)
        
        if not force_refresh:
            existing = check_screenshot_exists(url_hash)
            if existing['exists']:
                logger.info(f"Returning cached screenshot for {url}")
                return jsonify({
                    'success': True,
                    'cached': True,
                    'url': url,
                    'thumbnail_url': existing['thumbnail_url'],
                    'full_url': existing['full_url'],
                    'timestamp': datetime.utcnow().isoformat()
                })
        
        logger.info(f"Capturing new screenshot for {url}")
        screenshot_data = capture_screenshot(url)
        
        thumbnail_data = create_thumbnail(screenshot_data, THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT)
        
        screenshot_key = f"screenshots/{url_hash}.png"
        thumbnail_key = f"thumbnails/{url_hash}.png"
        
        full_url = upload_to_s3(screenshot_data, screenshot_key)
        thumbnail_url = upload_to_s3(thumbnail_data, thumbnail_key)
        
        logger.info(f"Screenshot saved successfully for {url}")
        
        return jsonify({
            'success': True,
            'cached': False,
            'url': url,
            'thumbnail_url': thumbnail_url,
            'full_url': full_url,
            'timestamp': datetime.utcnow().isoformat()
        })
        
    except Exception as e:
        logger.error(f"Error processing screenshot request: {str(e)}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@app.route('/screenshot/batch', methods=['POST'])
def create_batch_screenshots():
    try:
        data = request.get_json()
        
        if not data or 'urls' not in data:
            return jsonify({'error': 'URLs array is required'}), 400
        
        urls = data['urls']
        force_refresh = data.get('force_refresh', False)
        
        if not isinstance(urls, list) or len(urls) == 0:
            return jsonify({'error': 'URLs must be a non-empty array'}), 400
        
        if len(urls) > 10:
            return jsonify({'error': 'Maximum 10 URLs per batch request'}), 400
        
        results = []
        
        for url in urls:
            try:
                if not validate_url(url):
                    results.append({
                        'url': url,
                        'success': False,
                        'error': 'Invalid URL format'
                    })
                    continue
                
                url_hash = generate_url_hash(url)
                
                if not force_refresh:
                    existing = check_screenshot_exists(url_hash)
                    if existing['exists']:
                        results.append({
                            'url': url,
                            'success': True,
                            'cached': True,
                            'thumbnail_url': existing['thumbnail_url'],
                            'full_url': existing['full_url']
                        })
                        continue
                
                screenshot_data = capture_screenshot(url)
                thumbnail_data = create_thumbnail(screenshot_data, THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT)
                
                screenshot_key = f"screenshots/{url_hash}.png"
                thumbnail_key = f"thumbnails/{url_hash}.png"
                
                full_url = upload_to_s3(screenshot_data, screenshot_key)
                thumbnail_url = upload_to_s3(thumbnail_data, thumbnail_key)
                
                results.append({
                    'url': url,
                    'success': True,
                    'cached': False,
                    'thumbnail_url': thumbnail_url,
                    'full_url': full_url
                })
                
            except Exception as e:
                logger.error(f"Error processing URL {url}: {str(e)}")
                results.append({
                    'url': url,
                    'success': False,
                    'error': str(e)
                })
        
        return jsonify({
            'success': True,
            'results': results,
            'timestamp': datetime.utcnow().isoformat()
        })
        
    except Exception as e:
        logger.error(f"Error processing batch screenshot request: {str(e)}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@app.route('/screenshot/<url_hash>', methods=['GET'])
def get_screenshot(url_hash):
    try:
        existing = check_screenshot_exists(url_hash)
        
        if not existing['exists']:
            return jsonify({'error': 'Screenshot not found'}), 404
        
        return jsonify({
            'success': True,
            'thumbnail_url': existing['thumbnail_url'],
            'full_url': existing['full_url']
        })
        
    except Exception as e:
        logger.error(f"Error retrieving screenshot: {str(e)}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@app.route('/screenshot/<url_hash>', methods=['DELETE'])
def delete_screenshot(url_hash):
    try:
        screenshot_key = f"screenshots/{url_hash}.png"
        thumbnail_key = f"thumbnails/{url_hash}.png"
        
        s3_client.delete_object(Bucket=S3_BUCKET, Key=screenshot_key)
        s3_client.delete_object(Bucket=S3_BUCKET, Key=thumbnail_key)
        
        return jsonify({
            'success': True,
            'message': 'Screenshot deleted successfully'
        })
        
    except Exception as e:
        logger.error(f"Error deleting screenshot: {str(e)}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)